## Purpose
This is the CENTRAL COMPONENT that all other rich output flows through. FastMcpConsole wraps rich_rust's Console, adding:
1. Automatic agent detection (enable/disable styling)
2. Always writes to stderr (never stdout)
3. Plain-text fallbacks when rich is disabled
4. Integration with FastMCP's theme system
5. Global accessor for convenient use throughout codebase

## Critical Design Constraint: stderr Only
**FastMcpConsole MUST write to stderr, NEVER stdout.**

Why? Because stdout is reserved for JSON-RPC protocol messages:
- Agents parse stdout as NDJSON
- ANY non-JSON text on stdout corrupts the protocol
- All human-readable output goes to stderr
- This is the fundamental architectural decision enabling agent compatibility

## Implementation

### File: crates/fastmcp-console/src/console.rs

```rust
//\! FastMCP Console wrapper for rich output to stderr.
//\!
//\! This module provides the central Console abstraction that automatically
//\! handles agent detection, theming, and fallback to plain text.

use rich_rust::prelude::*;
use std::io::{self, Write};
use std::sync::OnceLock;

use crate::detection::should_enable_rich;
use crate::theme::{theme, FastMcpTheme};

/// FastMCP console for rich output to stderr
pub struct FastMcpConsole {
    inner: Console,
    enabled: bool,
}

impl FastMcpConsole {
    /// Create with automatic detection
    pub fn new() -> Self {
        let enabled = should_enable_rich();
        Self::with_enabled(enabled)
    }

    /// Create with explicit enable/disable
    pub fn with_enabled(enabled: bool) -> Self {
        let inner = if enabled {
            Console::builder()
                .file(Box::new(io::stderr()))
                .force_terminal(true)
                .markup(true)
                .emoji(true)
                .build()
        } else {
            Console::builder()
                .file(Box::new(io::stderr()))
                .color_system(None)  // Disable colors entirely
                .markup(false)
                .emoji(false)
                .build()
        };

        Self { inner, enabled }
    }

    /// Create with custom writer (for testing)
    pub fn with_writer<W: Write + Send + 'static>(writer: W, enabled: bool) -> Self {
        let inner = Console::builder()
            .file(Box::new(writer))
            .color_system(if enabled { None } else { None })
            .markup(enabled)
            .emoji(enabled)
            .build();

        Self { inner, enabled }
    }

    // ─────────────────────────────────────────────────
    // State Queries
    // ─────────────────────────────────────────────────

    /// Check if rich output is enabled
    pub fn is_rich(&self) -> bool {
        self.enabled
    }

    /// Get the theme
    pub fn theme(&self) -> &'static FastMcpTheme {
        theme()
    }

    /// Get terminal width (or default 80)
    pub fn width(&self) -> usize {
        self.inner.width().unwrap_or(80)
    }

    /// Get terminal height (or default 24)
    pub fn height(&self) -> usize {
        self.inner.height().unwrap_or(24)
    }

    // ─────────────────────────────────────────────────
    // Output Methods
    // ─────────────────────────────────────────────────

    /// Print content with markup parsing (if enabled)
    pub fn print(&self, content: &str) {
        if self.enabled {
            self.inner.print(content);
        } else {
            eprintln\!("{}", strip_markup(content));
        }
    }

    /// Print plain text (no markup processing ever)
    pub fn print_plain(&self, text: &str) {
        eprintln\!("{}", text);
    }

    /// Print a renderable (table, panel, etc.)
    pub fn render<'a>(&self, renderable: impl Fn() -> Vec<Segment<'a>>) {
        if self.enabled {
            let segments = renderable();
            for segment in segments {
                self.inner.print_segment(&segment);
            }
        }
        // Plain fallback: caller should provide alternative
    }

    /// Print a renderable with plain-text fallback
    pub fn render_or<'a, F>(&self, renderable: F, plain_fallback: &str)
    where
        F: FnOnce(&Console) -> (),
    {
        if self.enabled {
            renderable(&self.inner);
        } else {
            eprintln\!("{}", plain_fallback);
        }
    }

    // ─────────────────────────────────────────────────
    // Convenience Methods
    // ─────────────────────────────────────────────────

    /// Print a horizontal rule
    pub fn rule(&self, title: Option<&str>) {
        if self.enabled {
            let rule = match title {
                Some(t) => Rule::with_title(t).style(self.theme().border_style.clone()),
                None => Rule::new().style(self.theme().border_style.clone()),
            };
            self.inner.print_renderable(&rule);
        } else {
            match title {
                Some(t) => eprintln\!("--- {} ---", t),
                None => eprintln\!("---"),
            }
        }
    }

    /// Print a blank line
    pub fn newline(&self) {
        eprintln\!();
    }

    /// Print styled text with a specific style
    pub fn print_styled(&self, text: &str, style: &Style) {
        if self.enabled {
            self.inner.print_styled(text, style.clone());
        } else {
            eprintln\!("{}", text);
        }
    }

    /// Print a table (with plain fallback)
    pub fn print_table(&self, table: &Table, plain_fallback: &str) {
        if self.enabled {
            self.inner.print_renderable(table);
        } else {
            eprintln\!("{}", plain_fallback);
        }
    }

    /// Print a panel (with plain fallback)
    pub fn print_panel(&self, panel: &Panel, plain_fallback: &str) {
        if self.enabled {
            self.inner.print_renderable(panel);
        } else {
            eprintln\!("{}", plain_fallback);
        }
    }
}

impl Default for FastMcpConsole {
    fn default() -> Self {
        Self::new()
    }
}

// ─────────────────────────────────────────────────────────
// Global Console Accessor
// ─────────────────────────────────────────────────────────

static CONSOLE: OnceLock<FastMcpConsole> = OnceLock::new();

/// Get the global FastMCP console instance
pub fn console() -> &'static FastMcpConsole {
    CONSOLE.get_or_init(FastMcpConsole::new)
}

/// Initialize the global console with specific settings
/// Must be called before any output; returns error if already initialized
pub fn init_console(enabled: bool) -> Result<(), &'static str> {
    CONSOLE.set(FastMcpConsole::with_enabled(enabled))
        .map_err(|_| "Console already initialized")
}

// ─────────────────────────────────────────────────────────
// Helpers
// ─────────────────────────────────────────────────────────

/// Strip markup tags from text (for plain output)
fn strip_markup(text: &str) -> String {
    // Simple regex to remove [tag] and [/tag] patterns
    // In practice, use rich_rust's internal function if exposed
    let re = regex::Regex::new(r"\[/?[^\]]*\]").unwrap();
    re.replace_all(text, "").to_string()
}
